(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn27"],{6877:function(n,t){n.exports="### PHP\n\n在mac上配置Apache服务器\n```\n//开启apache:  sudo apachectl start\n//重启apache:  sudo apachectl restart\n//关闭apache:  sudo apachectl stop\n```\n用vim编辑httpd.conf\n```\ncd /etc/apache2\n```\n查找DocumentRoot  \n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/php/aaa.jpg)\n再查找下 php\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/php/bbb.jpg)\nphp.int的目录位置\n```\n/private/etc/php.ini\n```\nApache配置多个监听端口和不同的网站目录的简单方法\n```s\n打开Apache的配置文件httpd.conf\n在Listen 80\n下面添加多个监听端口如\nListen 8011\nListen 8088\n\n这样就增加了8011和8088端口的监听\n\n然后在最后的位置设置虚拟主机目录\nNameVirtualHost *:80\n<VirtualHost *:80>\nServerName localhost\nDocumentRoot “E:/web1″\n</VirtualHost>\n\n像这样，重启Apache服务，即可以用\nlocalhost\nlocalhost:8088\n访问你不同的网站了\n```\n\n解决php服务器(apache)下403 Forbidden错误的方法\n```s\n打开apache的配置文件httpd.conf，逐行检查\n找到：\n<Directory/>\n  Options FollowSymLinks\n  AllowOverride None\n  Order deny,allow\n  Deny from all\n</Directory>\n修改后的代码为：\n<Directory />\n  Options FollowSymLinks\n  AllowOverride None\n  Order deny,allow\n  allow from all\n</Directory>\n```"},cd96:function(n,t,e){"use strict";e.r(t);var o=function(){var n=this,t=n.$createElement,o=n._self._c||t;return o("markdown",{attrs:{source:e("6877")}})},a=[],c=e("2877"),r={},p=Object(c["a"])(r,o,a,!1,null,null,null);p.options.__file="php.vue";t["default"]=p.exports}}]);